import { randomUUID } from 'node:crypto';

import { BadRequestException, Injectable, Logger } from '@nestjs/common';
import { InjectQueue } from '@nestjs/bullmq';
import { Queue } from 'bullmq';

import { CacheService } from '@modules/cache/cache.service';
import { Namespaces } from '@modules/cache/types/cache.interface';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
import { JiraApiService } from '@modules/jira/jira-api.service';
import { IJiraInstallationBase } from '@modules/jira/types/jira-installation.interface';

import { JIRA_CLIENT_ID, JIRA_CALLBACK_URL } from '@constants/env-variables.constant';

interface IInstallStateValue {
	companyId: string;
	userId: string;
}

const STATE_TTL_MS = 5 * 60 * 1000;
const ATLASSIAN_AUTH_URL = 'https://auth.atlassian.com/authorize';

@Injectable()
export class JiraInstallService {
	private readonly logger = new Logger(JiraInstallService.name);

	constructor(
		private readonly configService: EnvConfigService,
		private readonly cacheService: CacheService,
		private readonly jiraApiService: JiraApiService,
		private readonly installationModel: JiraInstallationModel,
		@InjectQueue('jira') private readonly jiraQueue: Queue,
	) {}

	async initiateConnect({
		companyId,
		userId,
	}: {
		companyId: string;
		userId: string;
	}): Promise<string> {
		const state = randomUUID();

		await this.cacheService.set({
			namespace: Namespaces.JIRA_INSTALL_STATE,
			key: state,
			value: { companyId, userId } satisfies IInstallStateValue,
			ttl: STATE_TTL_MS,
		});

		const clientId = this.configService.get<string>({ key: JIRA_CLIENT_ID });
		const redirectUri = this.configService.get<string>({ key: JIRA_CALLBACK_URL });
		const scopes = 'read:jira-work read:jira-user offline_access';

		return (
			`${ATLASSIAN_AUTH_URL}?audience=api.atlassian.com` +
			`&client_id=${clientId}` +
			`&scope=${encodeURIComponent(scopes)}` +
			`&redirect_uri=${encodeURIComponent(redirectUri)}` +
			`&state=${state}` +
			`&response_type=code` +
			`&prompt=consent`
		);
	}

	async handleCallback({
		code,
		state,
	}: {
		code: string;
		state: string;
	}): Promise<IJiraInstallationBase> {
		const stateData = await this.cacheService.get<IInstallStateValue>({
			namespace: Namespaces.JIRA_INSTALL_STATE,
			key: state,
		});

		if (!stateData) {
			throw new BadRequestException('Invalid or expired state token');
		}

		await this.cacheService.deleteOne({
			namespace: Namespaces.JIRA_INSTALL_STATE,
			key: state,
		});

		const tokens = await this.jiraApiService.exchangeCode({ code });

		const resources = await this.jiraApiService.getAccessibleResources({
			accessToken: tokens.access_token,
		});

		const resource = resources[0];

		if (!resource) {
			throw new BadRequestException('No Jira Cloud sites found for this account');
		}

		const tokenExpiresAt = new Date(Date.now() + tokens.expires_in * 1000);

		const installation = await this.installationModel.create({
			data: {
				company_id: stateData.companyId,
				cloud_id: resource.id,
				site_url: resource.url,
				access_token: tokens.access_token,
				refresh_token: tokens.refresh_token,
				token_expires_at: tokenExpiresAt,
			},
		});

		void this.jiraQueue.add(
			'discover_projects',
			{ installationDbId: installation._id },
			{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
		);

		this.logger.debug(`Created jira installation ${installation._id} for company ${stateData.companyId}`);
		return installation;
	}

	async disconnect({
		installationDbId,
		companyId,
	}: {
		installationDbId: string;
		companyId: string;
	}): Promise<void> {
		await this.installationModel.markUninstalled({
			id: installationDbId,
			companyId,
		});

		this.logger.debug(`Disconnected jira installation ${installationDbId} for company ${companyId}`);
	}
}
